function paramsToListParams(
  sp: URLSearchParams,
): TicketListParams & {
  sortBy: TicketSortColumn;
  sortDir: "asc" | "desc";
  page: number;
} {
  const status = sp.get("status") as TicketStatus | null;
  const assignee = sp.get("assignee");
  const team = sp.get("team");
  const rcdo = sp.get("rcdo");
  const week = sp.get("week");
  const priority = sp.get("priority") as TicketPriority | null;
  return {
    ...(status ? { status } : {}),
    ...(assignee ? { assigneeUserId: assignee } : {}),
    ...(team ? { teamId: team } : {}),
    ...(rcdo ? { rcdoNodeId: rcdo } : {}),
    ...(week ? { targetWeek: week } : {}),
    ...(priority ? { priority } : {}),
    page: sp.get("page") ? Number(sp.get("page")) : 1,
    pageSize: PAGE_SIZE,
    sortBy: (sp.get("sortBy") as TicketSortColumn | null) ?? "updatedAt",
    sortDir: sp.get("sortDir") === "asc" ? "asc" : "desc",
  };
}

function buildRcdoLabels(
  nodes: ReturnType<typeof useRcdoTree>["data"],
): Record<string, string> {
  const map: Record<string, string> = {};
  function traverse(
    ns: typeof nodes,
    path: string[] = [],
  ) {
    if (!ns) return;
    for (const n of ns) {
      const nextPath = [...path, n.title];
      map[n.id] = nextPath.join(" > ");
      traverse(n.children, nextPath);
    }
  }
  traverse(nodes ?? []);
  return map;
}

