      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-team-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          Team
        </label>
        <input
          id="tf-team-filter"
          type="text"
          placeholder="Team ID…"
          value={params.teamId ?? ""}
          onChange={(e) => {
            const v = e.target.value;
            onParamsChange({ ...(v ? { teamId: v } : {}), page: 1 });
          }}
          data-testid="filter-team"
          style={{ ...inputStyle, minWidth: "110px" }}
        />
      </div>

      {/* RCDO */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-rcdo-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          RCDO
        </label>
        <input
          id="tf-rcdo-filter"
          type="text"
          placeholder="RCDO node ID…"
          value={params.rcdoNodeId ?? ""}
          onChange={(e) => {
            const v = e.target.value;
            onParamsChange({ ...(v ? { rcdoNodeId: v } : {}), page: 1 });
          }}
          data-testid="filter-rcdo"
          style={{ ...inputStyle, minWidth: "110px" }}
        />
      </div>

      {/* Target Week */}
      <div style={{ display: "flex", flexDirection: "column", gap: "2px" }}>
        <label
          htmlFor="tf-week-filter"
          style={{ fontSize: "0.7rem", fontWeight: 700, color: "var(--color-text-muted)", textTransform: "uppercase" }}
        >
          Target Week
        </label>
        <input
          id="tf-week-filter"
          type="date"
          value={params.targetWeek ?? ""}
          onChange={(e) => {
            const v = e.target.value;
            onParamsChange({ ...(v ? { targetWeek: v } : {}), page: 1 });
          }}
          data-testid="filter-week"
          style={inputStyle}
        />
      </div>

      {/* Clear all */}
      {hasFilter && (
        <button
          type="button"
          onClick={onClearFilters}
          data-testid="filter-clear-all"
          style={{
            padding: "0.35rem 0.75rem",
            border: "1px solid var(--color-border)",
            borderRadius: "var(--border-radius)",
            background: "var(--color-surface)",
            cursor: "pointer",
            fontFamily: "inherit",
            fontSize: "0.8rem",
            alignSelf: "flex-end",
          }}
        >
          ✕ Clear all
        </button>
      )}
    </div>
  );
}

// ── Tickets page ──────────────────────────────────────────────────────────────

export default function Tickets() {
  const bridge = useHostBridge();
  const currentUserId = bridge.context.authenticatedUser.id;
  const currentTeamId = bridge.context.currentTeam?.id;

  const [searchParams, setSearchParams] = useSearchParams();
  const listParams = useMemo(
    () => paramsToListParams(searchParams),
    [searchParams],
  );

  const { data: rcdoTreeData } = useRcdoTree();
  const rcdoLabels = useMemo(
    () => buildRcdoLabels(rcdoTreeData),
    [rcdoTreeData],
  );

  // Fetch ticket list
  const {
    data: ticketPage,
    loading: ticketsLoading,
    refetch: refetchTickets,
  } = useTicketList(listParams);

  const ticketApi = useTicketApi();

  // Selected ticket for detail view
  const [selectedTicketId, setSelectedTicketId] = useState<string | null>(null);
  const {
    data: ticketDetail,
    loading: detailLoading,
    refetch: refetchDetail,
  } = useTicket(selectedTicketId);

  // Form state
  type FormMode = "create" | "create-from-commit" | null;
  const [formMode, setFormMode] = useState<FormMode>(null);
  const [formInitialValues, setFormInitialValues] = useState<
    Partial<CreateTicketPayload>
  >({});

  // ── Param update helper ──────────────────────────────────────────────────

  const updateParams = useCallback(
    (patch: Partial<ReturnType<typeof paramsToListParams>>) => {
      setSearchParams((prev) => {
        const next = new URLSearchParams(prev);
        const merged = { ...paramsToListParams(prev), ...patch };
        const pairs: [string, string][] = [
          ...(merged.status ? [["status", merged.status] as [string, string]] : []),
          ...(merged.assigneeUserId ? [["assignee", merged.assigneeUserId] as [string, string]] : []),
          ...(merged.teamId ? [["team", merged.teamId] as [string, string]] : []),
          ...(merged.rcdoNodeId ? [["rcdo", merged.rcdoNodeId] as [string, string]] : []),
          ...(merged.targetWeek ? [["week", merged.targetWeek] as [string, string]] : []),
          ...(merged.priority ? [["priority", merged.priority] as [string, string]] : []),
          ...(merged.page && merged.page !== 1 ? [["page", String(merged.page)] as [string, string]] : []),
          ...(merged.sortBy && merged.sortBy !== "updatedAt" ? [["sortBy", merged.sortBy] as [string, string]] : []),
          ...(merged.sortDir && merged.sortDir !== "desc" ? [["sortDir", merged.sortDir] as [string, string]] : []),
        ];
        // Start fresh
        Array.from(next.keys()).forEach((k) => next.delete(k));
        pairs.forEach(([k, v]) => next.set(k, v));
        return next;
      });
    },
    [setSearchParams],
  );

  // ── Create ticket handler ────────────────────────────────────────────────

  const handleCreateTicket = useCallback(
    async (payload: CreateTicketPayload) => {
      await ticketApi.createTicket(payload);
      setFormMode(null);
      setFormInitialValues({});
      refetchTickets();
    },
    [ticketApi, refetchTickets],
  );

  // ── Status transition ────────────────────────────────────────────────────

  const handleStatusTransition = useCallback(
    async (ticketId: string, newStatus: TicketStatus) => {
      await ticketApi.updateTicket(ticketId, { status: newStatus });
      refetchDetail();
      refetchTickets();
    },
    [ticketApi, refetchDetail, refetchTickets],
  );

  // ── Assignment change ────────────────────────────────────────────────────

  const handleAssigneeChange = useCallback(
    async (ticketId: string, assigneeUserId: string) => {
      await ticketApi.updateTicket(
        ticketId,
        assigneeUserId
          ? { assigneeUserId }
          : {},
      );
      refetchDetail();
      refetchTickets();
    },
    [ticketApi, refetchDetail, refetchTickets],
  );

  const btnPrimary: React.CSSProperties = {
    padding: "0.5rem 1rem",
    border: "none",
    borderRadius: "var(--border-radius)",
    background: "var(--color-primary)",
    color: "#fff",
    cursor: "pointer",
    fontFamily: "inherit",
    fontSize: "0.875rem",
    fontWeight: 600,
  };

  return (
    <div
      className="route-page"
      data-testid="page-tickets"
      style={{ display: "flex", flexDirection: "column", gap: "1rem" }}
    >
      {/* Page header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          flexWrap: "wrap",
          gap: "0.5rem",
        }}
      >
        <h2 style={{ margin: 0, fontSize: "1.25rem" }}>Tickets</h2>
        <button
          type="button"
          style={btnPrimary}
          onClick={() => {
            setFormInitialValues({
              reporterUserId: currentUserId,
              ...(currentTeamId ? { teamId: currentTeamId } : {}),
            });
            setFormMode("create");
          }}
          data-testid="create-ticket-btn"
        >
          + Create Ticket
        </button>
      </div>

      {/* Filters */}
      <TicketFilters
        params={listParams}
        onParamsChange={updateParams}
        onClearFilters={() => setSearchParams(new URLSearchParams())}
      />

      {/* Ticket count summary */}
      {ticketPage && (
        <div
          data-testid="ticket-count"
          style={{ fontSize: "0.85rem", color: "var(--color-text-muted)" }}
        >
          {ticketPage.total} ticket{ticketPage.total !== 1 ? "s" : ""}
        </div>
      )}

      {/* Main content: list + optional detail panel */}
      <div
        style={{
          display: "flex",
          gap: "1rem",
          alignItems: "flex-start",
          flexWrap: selectedTicketId ? "nowrap" : "wrap",
        }}
      >
        {/* Ticket list */}
        <div
          style={{
            flex: selectedTicketId ? "0 0 55%" : "1 1 100%",
            minWidth: 0,
          }}
        >
          <TicketListView
            tickets={ticketPage?.items ?? []}
            total={ticketPage?.total ?? 0}
            page={listParams.page ?? 1}
            pageSize={PAGE_SIZE}
            sortBy={listParams.sortBy}
            sortDir={listParams.sortDir}
            loading={ticketsLoading}
            onPageChange={(p) => updateParams({ page: p })}
            onSortChange={(col, dir) => updateParams({ sortBy: col, sortDir: dir })}
            onSelectTicket={(id) =>
              setSelectedTicketId(id === selectedTicketId ? null : id)
            }
            rcdoLabels={rcdoLabels}
          />
        </div>

        {/* Detail panel */}
        {selectedTicketId && (
          <div
            data-testid="ticket-detail-panel"
            style={{
              flex: "1 1 42%",
              minWidth: "280px",
              position: "sticky",
              top: "1rem",
            }}
          >
            {detailLoading && (
              <div
                data-testid="ticket-detail-loading"
                role="status"
                style={{ color: "var(--color-text-muted)", padding: "1rem" }}
              >
                Loading…
              </div>
            )}
            {!detailLoading && ticketDetail && (
              <TicketDetailView
                ticket={ticketDetail}
                onStatusTransition={handleStatusTransition}
                onAssigneeChange={handleAssigneeChange}
                {...(ticketDetail.rcdoNodeId && rcdoLabels[ticketDetail.rcdoNodeId]
                  ? { rcdoPath: rcdoLabels[ticketDetail.rcdoNodeId] }
                  : {})}
                onClose={() => setSelectedTicketId(null)}
                onEdit={() => {
                  setFormInitialValues({
                    title: ticketDetail.title,
                    ...(ticketDetail.description ? { description: ticketDetail.description } : {}),
                    status: ticketDetail.status,
                    priority: ticketDetail.priority,
                    ...(ticketDetail.assigneeUserId ? { assigneeUserId: ticketDetail.assigneeUserId } : {}),
                    reporterUserId: ticketDetail.reporterUserId,
                    teamId: ticketDetail.teamId,
                    ...(ticketDetail.rcdoNodeId ? { rcdoNodeId: ticketDetail.rcdoNodeId } : {}),
                    ...(ticketDetail.estimatePoints != null ? { estimatePoints: ticketDetail.estimatePoints } : {}),
                    ...(ticketDetail.targetWeekStartDate ? { targetWeekStartDate: ticketDetail.targetWeekStartDate } : {}),
                  });
                  setFormMode("create"); // re-uses the form for editing
                }}
              />
            )}
          </div>
        )}
      </div>

      {/* Create Ticket form modal */}
      {formMode !== null && (
        <TicketForm
          mode="create"
          initialValues={formInitialValues}
          currentUserId={currentUserId}
          {...(currentTeamId ? { currentTeamId } : {})}
          onSubmit={handleCreateTicket}
          onCancel={() => {
            setFormMode(null);
            setFormInitialValues({});
          }}
        />
      )}
    </div>
  );
}

/**
 * TicketListView — sortable, paginated table of tickets.
 *
 * Columns: key, title, status, assignee, team, priority, RCDO, target week.
 * Filters are applied externally (passed via props from Tickets route).
 * Sortable columns trigger `onSortChange`.
 */
import type {
  TicketSummaryResponse,
  TicketStatus,
  TicketPriority,
} from "../../api/ticketTypes.js";
import {
  TICKET_STATUS_LABELS,
  TICKET_PRIORITY_LABELS,
} from "../../api/ticketTypes.js";

export type TicketSortColumn =
  | "key"
  | "title"
  | "status"
  | "priority"
  | "updatedAt";

export interface TicketListViewProps {
  readonly tickets: TicketSummaryResponse[];
  readonly total: number;
  readonly page: number;
  readonly pageSize: number;
  readonly sortBy: TicketSortColumn;
  readonly sortDir: "asc" | "desc";
  readonly loading: boolean;
  readonly onPageChange: (page: number) => void;
  readonly onSortChange: (col: TicketSortColumn, dir: "asc" | "desc") => void;
  readonly onSelectTicket: (ticketId: string) => void;
  /** Labels for RCDO nodes by id. */
  readonly rcdoLabels?: Record<string, string>;
}

const STATUS_BADGE_STYLES: Record<TicketStatus, React.CSSProperties> = {
  TODO: { background: "#f1f5f9", color: "#475569" },
  IN_PROGRESS: { background: "#dbeafe", color: "#1e40af" },
  DONE: { background: "#d1fae5", color: "#065f46" },
  CANCELED: { background: "#f1f5f9", color: "#94a3b8" },
  BLOCKED: { background: "#fee2e2", color: "#991b1b" },
};

const PRIORITY_BADGE_STYLES: Record<TicketPriority, React.CSSProperties> = {
  CRITICAL: { background: "#fee2e2", color: "#991b1b", fontWeight: 700 },
  HIGH: { background: "#fef3c7", color: "#92400e" },
  MEDIUM: { background: "#eff6ff", color: "#1e40af" },
  LOW: { background: "#f1f5f9", color: "#475569" },
};

function StatusBadge({ status }: { readonly status: TicketStatus }) {
  return (
    <span
      style={{
        ...STATUS_BADGE_STYLES[status],
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "0.7rem",
        fontWeight: 600,
        display: "inline-block",
        whiteSpace: "nowrap",
      }}
    >
      {TICKET_STATUS_LABELS[status]}
    </span>
  );
}

function PriorityBadge({ priority }: { readonly priority: TicketPriority }) {
  return (
    <span
      style={{
        ...PRIORITY_BADGE_STYLES[priority],
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "0.7rem",
        display: "inline-block",
        whiteSpace: "nowrap",
      }}
    >
      {TICKET_PRIORITY_LABELS[priority]}
    </span>
  );
}

function SortIndicator({
  col,
  active,
  dir,
}: {
  readonly col: TicketSortColumn;
  readonly active: boolean;
  readonly dir: "asc" | "desc";
}) {
  void col;
  if (!active) return <span style={{ opacity: 0.3 }}>↕</span>;
  return <span>{dir === "asc" ? "↑" : "↓"}</span>;
}

const SORTABLE_COLUMNS: { col: TicketSortColumn; label: string }[] = [
  { col: "key", label: "Key" },
  { col: "title", label: "Title" },
  { col: "status", label: "Status" },
  { col: "priority", label: "Priority" },
  { col: "updatedAt", label: "Updated" },
];

export function TicketListView({
  tickets,
  total,
  page,
  pageSize,
  sortBy,
  sortDir,
  loading,
  onPageChange,
  onSortChange,
  onSelectTicket,
  rcdoLabels = {},
}: TicketListViewProps) {
  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  function handleSortClick(col: TicketSortColumn) {
    if (sortBy === col) {
      onSortChange(col, sortDir === "asc" ? "desc" : "asc");
    } else {
      onSortChange(col, "asc");
    }
  }

  const thStyle: React.CSSProperties = {
    padding: "0.5rem 0.625rem",
    textAlign: "left",
    fontSize: "0.75rem",
    fontWeight: 700,
    textTransform: "uppercase",
    letterSpacing: "0.04em",
    color: "var(--color-text-muted)",
    borderBottom: "2px solid var(--color-border)",
    whiteSpace: "nowrap",
    cursor: "pointer",
    userSelect: "none",
  };
  const tdStyle: React.CSSProperties = {
    padding: "0.5rem 0.625rem",
    fontSize: "0.875rem",
    borderBottom: "1px solid var(--color-border)",
    verticalAlign: "middle",
  };

  return (
    <div data-testid="ticket-list-view" style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
      {loading && (
        <div
          role="status"
          aria-label="Loading tickets"
          data-testid="ticket-list-loading"
          style={{ color: "var(--color-text-muted)", fontSize: "0.875rem", padding: "0.5rem" }}
        >
          Loading tickets…
        </div>
      )}

      {!loading && tickets.length === 0 && (
        <div
          data-testid="ticket-list-empty"
          style={{
            padding: "2rem",
            textAlign: "center",
            color: "var(--color-text-muted)",
            fontSize: "0.9rem",
          }}
        >
          No tickets found matching your filters.
        </div>
      )}

      {!loading && tickets.length > 0 && (
        <div style={{ overflowX: "auto" }}>
          <table
            data-testid="ticket-list-table"
            style={{
              width: "100%",
              borderCollapse: "collapse",
              fontSize: "0.875rem",
            }}
          >
            <thead>
              <tr>
                {SORTABLE_COLUMNS.map(({ col, label }) => (
                  <th
                    key={col}
                    style={thStyle}
                    onClick={() => handleSortClick(col)}
                    data-testid={`sort-col-${col}`}
                    aria-sort={
                      sortBy === col
                        ? sortDir === "asc"
                          ? "ascending"
                          : "descending"
                        : "none"
                    }
                  >
                    {label}{" "}
                    <SortIndicator
                      col={col}
                      active={sortBy === col}
                      dir={sortDir}
                    />
                  </th>
                ))}
                <th style={thStyle}>Assignee</th>
                <th style={thStyle}>Team</th>
                <th style={thStyle}>RCDO</th>
                <th style={thStyle}>Target Week</th>
              </tr>
            </thead>
            <tbody>
              {tickets.map((ticket) => (
                <tr
                  key={ticket.id}
                  data-testid={`ticket-row-${ticket.id}`}
                  onClick={() => onSelectTicket(ticket.id)}
                  style={{
                    cursor: "pointer",
                    transition: "background 0.1s",
                  }}
                  onMouseEnter={(e) => {
                    (e.currentTarget as HTMLTableRowElement).style.background =
                      "var(--color-background)";
                  }}
                  onMouseLeave={(e) => {
                    (e.currentTarget as HTMLTableRowElement).style.background =
                      "";
                  }}
                >
                  <td style={tdStyle}>
                    <span
                      data-testid={`ticket-key-${ticket.id}`}
                      style={{ fontFamily: "monospace", fontSize: "0.8rem", fontWeight: 600 }}
                    >
                      {ticket.key}
                    </span>
                  </td>
                  <td style={{ ...tdStyle, maxWidth: "250px" }}>
                    <span
                      data-testid={`ticket-title-${ticket.id}`}
                      style={{
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        whiteSpace: "nowrap",
                        display: "block",
                      }}
                    >
                      {ticket.title}
                    </span>
                  </td>
                  <td style={tdStyle}>
                    <StatusBadge status={ticket.status} />
                  </td>
                  <td style={tdStyle}>
                    <PriorityBadge priority={ticket.priority} />
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem", color: "var(--color-text-muted)" }}>
                    {new Date(ticket.updatedAt).toLocaleDateString()}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem" }}>
                    {ticket.assigneeUserId ?? (
                      <span style={{ color: "var(--color-text-muted)" }}>—</span>
                    )}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem" }}>
                    {ticket.teamId}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
                    {ticket.rcdoNodeId
                      ? (rcdoLabels[ticket.rcdoNodeId] ?? ticket.rcdoNodeId)
                      : "—"}
                  </td>
                  <td style={{ ...tdStyle, fontSize: "0.8rem" }}>
                    {ticket.targetWeekStartDate ?? (
                      <span style={{ color: "var(--color-text-muted)" }}>—</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Pagination */}
      {total > pageSize && (
        <div
          data-testid="ticket-list-pagination"
          style={{
            display: "flex",
            alignItems: "center",
            gap: "0.5rem",
            justifyContent: "flex-end",
            flexWrap: "wrap",
          }}
        >
          <span style={{ fontSize: "0.8rem", color: "var(--color-text-muted)" }}>
            {(page - 1) * pageSize + 1}–
            {Math.min(page * pageSize, total)} of {total}
          </span>
          <button
            type="button"
            onClick={() => onPageChange(page - 1)}
            disabled={page <= 1}
            data-testid="ticket-page-prev"
            style={{
              padding: "0.3rem 0.625rem",
              border: "1px solid var(--color-border)",
              borderRadius: "var(--border-radius)",
              background: "var(--color-surface)",
              cursor: page <= 1 ? "not-allowed" : "pointer",
              fontFamily: "inherit",
              fontSize: "0.8rem",
            }}
          >
            ◀ Prev
          </button>
          <span
            data-testid="ticket-page-indicator"
            style={{ fontSize: "0.8rem" }}
          >
            {page} / {totalPages}
          </span>
          <button
            type="button"
            onClick={() => onPageChange(page + 1)}
            disabled={page >= totalPages}
            data-testid="ticket-page-next"
            style={{
              padding: "0.3rem 0.625rem",
              border: "1px solid var(--color-border)",
              borderRadius: "var(--border-radius)",
              background: "var(--color-surface)",
              cursor: page >= totalPages ? "not-allowed" : "pointer",
              fontFamily: "inherit",
              fontSize: "0.8rem",
            }}
          >
            Next ▶
          </button>
        </div>
      )}
    </div>
  );
}

/**
 * TicketDetailView — full ticket detail panel.
 *
 * Shows:
 *   - Ticket key, title, status with transition buttons
 *   - Description
 *   - Priority, assignee, reporter, team, RCDO path, estimate, target week
 *   - Status history timeline
 *   - Linked commits list
 *   - Assignment change input
 */
import { useState, useCallback } from "react";
import type {
  TicketResponse,
  TicketStatus,
  TicketStatusHistory,
  LinkedCommitEntry,
} from "../../api/ticketTypes.js";
import type { CommitOutcome } from "../../api/planTypes.js";
import {
  TICKET_STATUS_LABELS,
  TICKET_STATUS_TRANSITIONS,
  TICKET_PRIORITY_LABELS,
} from "../../api/ticketTypes.js";

export interface TicketDetailViewProps {
  readonly ticket: TicketResponse;
  /** Called when status transition is requested. May throw to surface error. */
  readonly onStatusTransition: (ticketId: string, newStatus: TicketStatus) => Promise<void>;
  /** Called when assignee is changed. */
  readonly onAssigneeChange: (ticketId: string, assigneeUserId: string) => Promise<void>;
  /** Optional RCDO path label. */
  readonly rcdoPath?: string | undefined;
  readonly onClose?: () => void;
  readonly onEdit?: () => void;
}

const STATUS_COLORS: Record<TicketStatus, { bg: string; color: string }> = {
  TODO: { bg: "#f1f5f9", color: "#475569" },
  IN_PROGRESS: { bg: "#dbeafe", color: "#1e40af" },
  DONE: { bg: "#d1fae5", color: "#065f46" },
  CANCELED: { bg: "#f1f5f9", color: "#94a3b8" },
  BLOCKED: { bg: "#fee2e2", color: "#991b1b" },
};

const OUTCOME_LABELS: Record<CommitOutcome, string> = {
  ACHIEVED: "✓ Achieved",
  PARTIALLY_ACHIEVED: "◑ Partial",
  NOT_ACHIEVED: "✗ Not achieved",
  CANCELED: "— Canceled",
};
const OUTCOME_COLORS: Record<CommitOutcome, string> = {
  ACHIEVED: "var(--color-success)",
  PARTIALLY_ACHIEVED: "var(--color-warning)",
  NOT_ACHIEVED: "var(--color-danger)",
  CANCELED: "var(--color-text-muted)",
};

function StatusHistoryTimeline({
  history,
}: {
  readonly history: TicketStatusHistory[];
}) {
  if (history.length === 0) {
    return (
      <p
        data-testid="status-history-empty"
        style={{ fontSize: "0.875rem", color: "var(--color-text-muted)" }}
      >
        No status changes recorded.
      </p>
    );
  }

  return (
    <ol
      data-testid="status-history-timeline"
      style={{
        listStyle: "none",
        margin: 0,
        padding: 0,
        display: "flex",
        flexDirection: "column",
        gap: "0.5rem",
      }}
    >
      {[...history].reverse().map((entry) => (
        <li
          key={entry.id}
          data-testid={`history-entry-${entry.id}`}
          style={{
            display: "flex",
            alignItems: "flex-start",
            gap: "0.625rem",
            fontSize: "0.8rem",
          }}
        >
          <span
            style={{
              marginTop: "2px",
              width: "8px",
              height: "8px",
              borderRadius: "50%",
              background: "var(--color-primary)",
              flexShrink: 0,
            }}
          />
          <div>
            <span style={{ color: "var(--color-text-muted)" }}>
              {new Date(entry.changedAt).toLocaleString()}
            </span>{" "}
            —{" "}
            {entry.fromStatus ? (
              <>
                <strong>{TICKET_STATUS_LABELS[entry.fromStatus]}</strong>
                {" → "}
              </>
            ) : null}
            <strong>{TICKET_STATUS_LABELS[entry.toStatus]}</strong>
            {entry.note && (
              <span style={{ color: "var(--color-text-muted)" }}>
                {" "}({entry.note})
              </span>
            )}
          </div>
        </li>
      ))}
    </ol>
  );
}

function LinkedCommitsList({
  commits,
}: {
  readonly commits: LinkedCommitEntry[];
}) {
  if (commits.length === 0) {
    return (
      <p
        data-testid="linked-commits-empty"
        style={{ fontSize: "0.875rem", color: "var(--color-text-muted)" }}
      >
        No linked commits.
      </p>
    );
  }

  return (
    <ul
      data-testid="linked-commits-list"
      style={{
        listStyle: "none",
        margin: 0,
        padding: 0,
        display: "flex",
        flexDirection: "column",
        gap: "0.375rem",
      }}
    >
      {commits.map((c) => (
        <li
          key={c.commitId}
          data-testid={`linked-commit-${c.commitId}`}
          style={{
            background: "var(--color-background)",
            border: "1px solid var(--color-border)",
            borderRadius: "var(--border-radius)",
            padding: "0.5rem 0.75rem",
            fontSize: "0.85rem",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            flexWrap: "wrap",
            gap: "0.375rem",
          }}
        >
          <div>
            <span style={{ fontWeight: 600 }}>{c.commitTitle}</span>
            <span
              style={{
                marginLeft: "0.5rem",
                fontSize: "0.75rem",
                color: "var(--color-text-muted)",
              }}
            >
              {c.weekStartDate} · {c.chessPiece}
              {c.estimatePoints != null ? ` · ${c.estimatePoints}pts` : ""}
            </span>
          </div>
          {c.outcome && (
            <span
              data-testid={`linked-commit-outcome-${c.commitId}`}
              style={{
                fontSize: "0.75rem",
                color: OUTCOME_COLORS[c.outcome],
                fontWeight: 600,
              }}
            >
              {OUTCOME_LABELS[c.outcome]}
            </span>
          )}
        </li>
      ))}
    </ul>
  );
}

const sectionHeadingStyle: React.CSSProperties = {
  fontSize: "0.85rem",
  fontWeight: 700,
  textTransform: "uppercase",
  letterSpacing: "0.04em",
  color: "var(--color-text-muted)",
  margin: "0 0 0.5rem",
};

const metaRowStyle: React.CSSProperties = {
  display: "flex",
  gap: "0.375rem",
  fontSize: "0.875rem",
  alignItems: "baseline",
};

const metaLabelStyle: React.CSSProperties = {
  fontWeight: 600,
  minWidth: "100px",
  flexShrink: 0,
  color: "var(--color-text-muted)",
};

export function TicketDetailView({
  ticket,
  onStatusTransition,
  onAssigneeChange,
  rcdoPath,
  onClose,
  onEdit,
}: TicketDetailViewProps) {
  const [transitioning, setTransitioning] = useState<TicketStatus | null>(null);
  const [transitionError, setTransitionError] = useState<string | null>(null);
  const [assigneeInput, setAssigneeInput] = useState(ticket.assigneeUserId ?? "");
  const [assigneeSaving, setAssigneeSaving] = useState(false);
  const [assigneeError, setAssigneeError] = useState<string | null>(null);

  const nextStatuses = TICKET_STATUS_TRANSITIONS[ticket.status];

  const handleTransition = useCallback(
    async (newStatus: TicketStatus) => {
      setTransitioning(newStatus);
      setTransitionError(null);
      try {
        await onStatusTransition(ticket.id, newStatus);
      } catch (err) {
        setTransitionError(
          err instanceof Error ? err.message : "Status transition failed.",
        );
      } finally {
        setTransitioning(null);
      }
    },
    [ticket.id, onStatusTransition],
  );

  const handleAssigneeChange = useCallback(async () => {
    setAssigneeSaving(true);
    setAssigneeError(null);
    try {
      await onAssigneeChange(ticket.id, assigneeInput.trim());
    } catch (err) {
      setAssigneeError(
        err instanceof Error ? err.message : "Assignment change failed.",
      );
    } finally {
      setAssigneeSaving(false);
    }
  }, [ticket.id, assigneeInput, onAssigneeChange]);

  const { bg, color } = STATUS_COLORS[ticket.status];

  return (
    <div
      data-testid="ticket-detail-view"
      style={{
        background: "var(--color-surface)",
        border: "1px solid var(--color-border)",
        borderRadius: "var(--border-radius)",
        display: "flex",
        flexDirection: "column",
        gap: "1.25rem",
        overflow: "hidden",
      }}
    >
      {/* Header */}
      <div
        style={{
          padding: "1rem 1.25rem",
          borderBottom: "1px solid var(--color-border)",
          display: "flex",
          alignItems: "flex-start",
          justifyContent: "space-between",
          gap: "1rem",
          flexWrap: "wrap",
        }}
      >
        <div style={{ display: "flex", flexDirection: "column", gap: "0.375rem", flex: 1 }}>
          <div style={{ display: "flex", alignItems: "center", gap: "0.5rem", flexWrap: "wrap" }}>
            <span
              data-testid="ticket-detail-key"
              style={{
                fontFamily: "monospace",
                fontSize: "0.85rem",
                fontWeight: 700,
                color: "var(--color-text-muted)",
              }}
            >
              {ticket.key}
            </span>
            <span
              data-testid="ticket-detail-status-badge"
              style={{
                background: bg,
                color,
                padding: "2px 9px",
                borderRadius: "999px",
                fontSize: "0.75rem",
                fontWeight: 700,
              }}
            >
              {TICKET_STATUS_LABELS[ticket.status]}
            </span>
          </div>
          <h2
            data-testid="ticket-detail-title"
            style={{ margin: 0, fontSize: "1.1rem", fontWeight: 700 }}
          >
            {ticket.title}
          </h2>
        </div>

        {/* Action buttons */}
        <div style={{ display: "flex", gap: "0.5rem", flexShrink: 0 }}>
          {onEdit && (
            <button
              type="button"
              onClick={onEdit}
              data-testid="ticket-detail-edit-btn"
              style={{
                padding: "0.375rem 0.75rem",
                border: "1px solid var(--color-border)",
                borderRadius: "var(--border-radius)",
                background: "var(--color-surface)",
                cursor: "pointer",
                fontFamily: "inherit",
                fontSize: "0.8rem",
              }}
            >
              ✏ Edit
            </button>
          )}
          {onClose && (
            <button
              type="button"
              onClick={onClose}
              aria-label="Close ticket detail"
              data-testid="ticket-detail-close-btn"
              style={{
                padding: "0.375rem 0.5rem",
                border: "none",
                borderRadius: "var(--border-radius)",
                background: "none",
                cursor: "pointer",
                fontSize: "1rem",
                color: "var(--color-text-muted)",
              }}
            >
              ✕
            </button>
          )}
        </div>
      </div>

      <div style={{ padding: "0 1.25rem 1.25rem", display: "flex", flexDirection: "column", gap: "1.25rem" }}>
        {/* Status transitions */}
        {nextStatuses.length > 0 && (
          <div>
            <p style={sectionHeadingStyle}>Status Transitions</p>
            <div
              data-testid="status-transition-buttons"
              style={{ display: "flex", gap: "0.375rem", flexWrap: "wrap" }}
            >
              {nextStatuses.map((next) => (
                <button
                  key={next}
                  type="button"
                  onClick={() => void handleTransition(next)}
                  disabled={transitioning !== null}
                  data-testid={`transition-btn-${next.toLowerCase()}`}
                  style={{
                    padding: "0.375rem 0.875rem",
                    border: "1px solid var(--color-border)",
                    borderRadius: "var(--border-radius)",
                    background: STATUS_COLORS[next].bg,
                    color: STATUS_COLORS[next].color,
                    cursor: transitioning !== null ? "not-allowed" : "pointer",
                    fontFamily: "inherit",
                    fontSize: "0.8rem",
                    fontWeight: 600,
                  }}
                >
                  {transitioning === next
                    ? "…"
                    : `→ ${TICKET_STATUS_LABELS[next]}`}
                </button>
              ))}
            </div>
            {transitionError && (
              <span
                data-testid="transition-error"
                role="alert"
                style={{ fontSize: "0.8rem", color: "var(--color-danger)", marginTop: "0.375rem", display: "block" }}
              >
                {transitionError}
              </span>
            )}
          </div>
        )}

        {/* Description */}
        {ticket.description && (
          <div>
            <p style={sectionHeadingStyle}>Description</p>
            <p
              data-testid="ticket-detail-description"
              style={{ margin: 0, fontSize: "0.875rem", lineHeight: 1.6 }}
            >
              {ticket.description}
            </p>
          </div>
        )}

        {/* Metadata */}
        <div>
          <p style={sectionHeadingStyle}>Details</p>
          <div
            data-testid="ticket-detail-meta"
            style={{ display: "flex", flexDirection: "column", gap: "0.375rem" }}
          >
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Priority</span>
              <span data-testid="ticket-detail-priority">
                {TICKET_PRIORITY_LABELS[ticket.priority]}
              </span>
            </div>
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Reporter</span>
              <span data-testid="ticket-detail-reporter">{ticket.reporterUserId}</span>
            </div>
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Team</span>
              <span data-testid="ticket-detail-team">{ticket.teamId}</span>
            </div>
            {ticket.rcdoNodeId && (
              <div style={metaRowStyle}>
                <span style={metaLabelStyle}>RCDO</span>
                <span data-testid="ticket-detail-rcdo">
                  {rcdoPath ?? ticket.rcdoNodeId}
                </span>
              </div>
            )}
            {ticket.estimatePoints != null && (
              <div style={metaRowStyle}>
                <span style={metaLabelStyle}>Estimate</span>
                <span data-testid="ticket-detail-estimate">
                  {ticket.estimatePoints} pts
                </span>
              </div>
            )}
            {ticket.targetWeekStartDate && (
              <div style={metaRowStyle}>
                <span style={metaLabelStyle}>Target Week</span>
                <span data-testid="ticket-detail-target-week">
                  {ticket.targetWeekStartDate}
                </span>
              </div>
            )}
            <div style={metaRowStyle}>
              <span style={metaLabelStyle}>Created</span>
              <span>{new Date(ticket.createdAt).toLocaleString()}</span>
            </div>
          </div>
        </div>

        {/* Assignment change */}
        <div>
          <p style={sectionHeadingStyle}>Assignment</p>
          <div
            data-testid="ticket-assignment-section"
            style={{ display: "flex", gap: "0.5rem", alignItems: "center", flexWrap: "wrap" }}
          >
            <input
              type="text"
              value={assigneeInput}
              onChange={(e) => setAssigneeInput(e.target.value)}
              placeholder="User ID (leave blank to unassign)"
              data-testid="ticket-assignee-input"
              style={{
                padding: "0.4rem 0.625rem",
                border: "1px solid var(--color-border)",
                borderRadius: "var(--border-radius)",
                background: "var(--color-surface)",
                color: "var(--color-text)",
                fontFamily: "inherit",
                fontSize: "0.875rem",
                minWidth: "180px",
              }}
            />
            <button
              type="button"
              onClick={() => void handleAssigneeChange()}
              disabled={assigneeSaving}
              data-testid="ticket-assign-save-btn"
              style={{
                padding: "0.4rem 0.875rem",
                border: "none",
                borderRadius: "var(--border-radius)",
                background: "var(--color-primary)",
                color: "#fff",
                cursor: assigneeSaving ? "not-allowed" : "pointer",
                fontFamily: "inherit",
                fontSize: "0.875rem",
                fontWeight: 600,
              }}
            >
              {assigneeSaving ? "Saving…" : "Update"}
            </button>
          </div>
          {assigneeError && (
            <span
              data-testid="assignee-error"
              role="alert"
              style={{ fontSize: "0.8rem", color: "var(--color-danger)", marginTop: "0.375rem", display: "block" }}
            >
              {assigneeError}
            </span>
          )}
        </div>

        {/* Status history */}
        <div>
          <p style={sectionHeadingStyle}>Status History</p>
          <StatusHistoryTimeline history={ticket.statusHistory} />
        </div>

        {/* Linked commits */}
        <div>
          <p style={sectionHeadingStyle}>Linked Commits</p>
          <LinkedCommitsList commits={ticket.linkedCommits} />
        </div>
      </div>
    </div>
  );
}

/**
 * TicketForm — modal form for creating or editing a native ticket.
 *
 * Fields:
 *   - title (required)
 *   - description (textarea)
 *   - status (select, default Backlog/TODO)
 *   - priority (required select)
 *   - assignee (text input for userId)
 *   - reporter (default = current user, read-only when pre-filled)
 *   - team (text input for teamId)
 *   - estimatePoints (optional Fibonacci select)
 *   - rcdoNodeId (optional text input)
 *   - targetWeekStartDate (optional date input)
 *
 * Supports "create-from-commit" mode via `initialValues` prop.
 */
import { useState, type FormEvent } from "react";
import type {
  CreateTicketPayload,
  TicketStatus,
  TicketPriority,
  TicketResponse,
} from "../../api/ticketTypes.js";
import type { EstimatePoints } from "../../api/planTypes.js";
import {
  TICKET_STATUS_LABELS,
  TICKET_PRIORITY_LABELS,
} from "../../api/ticketTypes.js";

const TICKET_STATUSES: TicketStatus[] = [
  "TODO",
  "IN_PROGRESS",
  "BLOCKED",
  "DONE",
  "CANCELED",
];
const TICKET_PRIORITIES: TicketPriority[] = [
  "CRITICAL",
  "HIGH",
  "MEDIUM",
  "LOW",
];
const ESTIMATE_POINTS: EstimatePoints[] = [1, 2, 3, 5, 8];

export interface TicketFormProps {
  readonly mode: "create" | "edit";
  /** Pre-populate fields (used for create-from-commit or editing). */
  readonly initialValues?: Partial<CreateTicketPayload>;
  readonly currentUserId: string;
  readonly currentTeamId?: string | undefined;
  /** Called with the full payload on submit. May throw to surface error in form. */
  readonly onSubmit: (payload: CreateTicketPayload) => Promise<void>;
  readonly onCancel: () => void;
  /** Optional existing ticket (edit mode). */
  readonly ticket?: TicketResponse;
}

const inputStyle: React.CSSProperties = {
  width: "100%",
  padding: "0.5rem 0.625rem",
  border: "1px solid var(--color-border)",
  borderRadius: "var(--border-radius)",
  background: "var(--color-surface)",
  color: "var(--color-text)",
  fontFamily: "inherit",
  fontSize: "0.875rem",
  boxSizing: "border-box",
};

const labelStyle: React.CSSProperties = {
  display: "block",
  fontSize: "0.8rem",
  fontWeight: 600,
  color: "var(--color-text-muted)",
  marginBottom: "0.3rem",
};

const fieldStyle: React.CSSProperties = {
  display: "flex",
  flexDirection: "column",
  gap: "0",
};

const errorStyle: React.CSSProperties = {
  fontSize: "0.75rem",
  color: "var(--color-danger)",
  marginTop: "0.25rem",
};

export function TicketForm({
  mode,
  initialValues,
  currentUserId,
  currentTeamId,
  onSubmit,
  onCancel,
  ticket,
}: TicketFormProps) {
  const [title, setTitle] = useState(
    ticket?.title ?? initialValues?.title ?? "",
  );
  const [description, setDescription] = useState(
    ticket?.description ?? initialValues?.description ?? "",
  );
  const [status, setStatus] = useState<TicketStatus>(
    ticket?.status ?? initialValues?.status ?? "TODO",
  );
  const [priority, setPriority] = useState<TicketPriority>(
    ticket?.priority ?? initialValues?.priority ?? "MEDIUM",
  );
  const [assignee, setAssignee] = useState(
    ticket?.assigneeUserId ?? initialValues?.assigneeUserId ?? "",
  );
  const [reporter, setReporter] = useState(
    ticket?.reporterUserId ?? initialValues?.reporterUserId ?? currentUserId,
  );
  const [teamId, setTeamId] = useState(
    ticket?.teamId ?? initialValues?.teamId ?? currentTeamId ?? "",
  );
  const [estimatePoints, setEstimatePoints] = useState<EstimatePoints | "">(
    ticket?.estimatePoints ?? initialValues?.estimatePoints ?? "",
  );
  const [rcdoNodeId, setRcdoNodeId] = useState(
    ticket?.rcdoNodeId ?? initialValues?.rcdoNodeId ?? "",
  );
  const [targetWeek, setTargetWeek] = useState(
    ticket?.targetWeekStartDate ?? initialValues?.targetWeekStartDate ?? "",
  );

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  function validate(): boolean {
    const next: Record<string, string> = {};
    if (!title.trim()) next.title = "Title is required.";
    if (!teamId.trim()) next.teamId = "Team is required.";
    if (!reporter.trim()) next.reporter = "Reporter is required.";
    setErrors(next);
    return Object.keys(next).length === 0;
  }

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    if (!validate()) return;
    setSaving(true);
    setSubmitError(null);
    try {
      const payload: CreateTicketPayload = {
        title: title.trim(),
        ...(description.trim() ? { description: description.trim() } : {}),
        status,
        priority,
        ...(assignee.trim() ? { assigneeUserId: assignee.trim() } : {}),
        reporterUserId: reporter.trim(),
        teamId: teamId.trim(),
        ...(rcdoNodeId.trim() ? { rcdoNodeId: rcdoNodeId.trim() } : {}),
        ...(estimatePoints !== ""
          ? { estimatePoints: estimatePoints as EstimatePoints }
          : {}),
        ...(targetWeek ? { targetWeekStartDate: targetWeek } : {}),
      };
      await onSubmit(payload);
    } catch (err) {
      setSubmitError(err instanceof Error ? err.message : "Failed to save ticket.");
    } finally {
      setSaving(false);
    }
  }

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label={mode === "create" ? "Create ticket" : "Edit ticket"}
      data-testid="ticket-form-dialog"
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1100,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "rgba(0,0,0,0.35)",
        overflow: "auto",
        padding: "1rem",
      }}
    >
      <div
        style={{
          background: "var(--color-surface)",
          border: "1px solid var(--color-border)",
          borderRadius: "var(--border-radius)",
          padding: "1.5rem",
          width: "min(520px, 96vw)",
          boxShadow: "0 8px 32px rgba(0,0,0,0.18)",
          maxHeight: "90vh",
          overflowY: "auto",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            marginBottom: "1.25rem",
          }}
        >
          <h3 style={{ margin: 0, fontSize: "1rem" }}>
            {mode === "create" ? "Create Ticket" : "Edit Ticket"}
          </h3>
          <button
            type="button"
            onClick={onCancel}
            aria-label="Close"
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: "1.1rem",
              color: "var(--color-text-muted)",
              padding: "0.25rem",
            }}
          >
            ✕
          </button>
        </div>

        <form onSubmit={(e) => void handleSubmit(e)} noValidate>
          <div style={{ display: "flex", flexDirection: "column", gap: "0.875rem" }}>
            {/* Title */}
            <div style={fieldStyle}>
              <label htmlFor="tf-title" style={labelStyle}>
                Title <span aria-hidden="true" style={{ color: "var(--color-danger)" }}>*</span>
              </label>
              <input
                id="tf-title"
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                data-testid="ticket-form-title"
                style={inputStyle}
                placeholder="Short descriptive title"
                required
              />
              {errors.title && (
                <span data-testid="ticket-form-title-error" style={errorStyle}>
                  {errors.title}
                </span>
              )}
            </div>

            {/* Description */}
            <div style={fieldStyle}>
              <label htmlFor="tf-desc" style={labelStyle}>
                Description
              </label>
              <textarea
                id="tf-desc"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                data-testid="ticket-form-description"
                style={{
                  ...inputStyle,
                  minHeight: "80px",
                  resize: "vertical",
                  fontFamily: "inherit",
                }}
                placeholder="Optional details…"
              />
            </div>

            {/* Status + Priority row */}
            <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
              <div style={{ ...fieldStyle, flex: 1, minWidth: "120px" }}>
                <label htmlFor="tf-status" style={labelStyle}>
                  Status
                </label>
                <select
                  id="tf-status"
                  value={status}
                  onChange={(e) => setStatus(e.target.value as TicketStatus)}
                  data-testid="ticket-form-status"
                  style={inputStyle}
                >
                  {TICKET_STATUSES.map((s) => (
                    <option key={s} value={s}>
                      {TICKET_STATUS_LABELS[s]}
                    </option>
                  ))}
                </select>
              </div>

              <div style={{ ...fieldStyle, flex: 1, minWidth: "120px" }}>
                <label htmlFor="tf-priority" style={labelStyle}>
                  Priority <span aria-hidden="true" style={{ color: "var(--color-danger)" }}>*</span>
                </label>
                <select
                  id="tf-priority"
                  value={priority}
                  onChange={(e) => setPriority(e.target.value as TicketPriority)}
                  data-testid="ticket-form-priority"
                  style={inputStyle}
                >
                  {TICKET_PRIORITIES.map((p) => (
                    <option key={p} value={p}>
                      {TICKET_PRIORITY_LABELS[p]}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            {/* Assignee */}
            <div style={fieldStyle}>
              <label htmlFor="tf-assignee" style={labelStyle}>
                Assignee (User ID)
              </label>
              <input
                id="tf-assignee"
                type="text"
                value={assignee}
                onChange={(e) => setAssignee(e.target.value)}
                data-testid="ticket-form-assignee"
                style={inputStyle}
                placeholder="Leave blank to leave unassigned"
              />
            </div>

            {/* Reporter */}
            <div style={fieldStyle}>
              <label htmlFor="tf-reporter" style={labelStyle}>
                Reporter <span aria-hidden="true" style={{ color: "var(--color-danger)" }}>*</span>
              </label>
              <input
                id="tf-reporter"
                type="text"
                value={reporter}
                onChange={(e) => setReporter(e.target.value)}
                data-testid="ticket-form-reporter"
                style={inputStyle}
              />
              {errors.reporter && (
                <span data-testid="ticket-form-reporter-error" style={errorStyle}>
                  {errors.reporter}
                </span>
              )}
            </div>

            {/* Team */}
            <div style={fieldStyle}>
              <label htmlFor="tf-team" style={labelStyle}>
                Team <span aria-hidden="true" style={{ color: "var(--color-danger)" }}>*</span>
              </label>
              <input
                id="tf-team"
                type="text"
                value={teamId}
                onChange={(e) => setTeamId(e.target.value)}
                data-testid="ticket-form-team"
                style={inputStyle}
                placeholder="Team ID"
              />
              {errors.teamId && (
                <span data-testid="ticket-form-team-error" style={errorStyle}>
                  {errors.teamId}
                </span>
              )}
            </div>

            {/* Estimate Points */}
            <div style={fieldStyle}>
              <label htmlFor="tf-points" style={labelStyle}>
                Estimate Points (optional)
              </label>
              <select
                id="tf-points"
                value={estimatePoints}
                onChange={(e) =>
                  setEstimatePoints(
                    e.target.value === ""
                      ? ""
                      : (Number(e.target.value) as EstimatePoints),
                  )
                }
                data-testid="ticket-form-estimate"
                style={inputStyle}
              >
                <option value="">Unestimated</option>
                {ESTIMATE_POINTS.map((p) => (
                  <option key={p} value={p}>
                    {p} {p === 1 ? "pt" : "pts"}
                  </option>
                ))}
              </select>
            </div>

            {/* RCDO link */}
            <div style={fieldStyle}>
              <label htmlFor="tf-rcdo" style={labelStyle}>
                RCDO Link (optional)
              </label>
              <input
                id="tf-rcdo"
                type="text"
                value={rcdoNodeId}
                onChange={(e) => setRcdoNodeId(e.target.value)}
                data-testid="ticket-form-rcdo"
                style={inputStyle}
                placeholder="RCDO node ID"
              />
            </div>

            {/* Target Week */}
            <div style={fieldStyle}>
              <label htmlFor="tf-target-week" style={labelStyle}>
                Target Week (optional)
              </label>
              <input
                id="tf-target-week"
                type="date"
                value={targetWeek}
                onChange={(e) => setTargetWeek(e.target.value)}
                data-testid="ticket-form-target-week"
                style={inputStyle}
              />
            </div>

            {/* Submit error */}
            {submitError && (
              <div
                role="alert"
                data-testid="ticket-form-submit-error"
                style={{
                  background: "#fef2f2",
                  border: "1px solid #fecaca",
                  borderRadius: "var(--border-radius)",
                  padding: "0.5rem 0.75rem",
                  fontSize: "0.8rem",
                  color: "var(--color-danger)",
                }}
              >
                {submitError}
              </div>
            )}

            {/* Actions */}
            <div
              style={{
                display: "flex",
                gap: "0.5rem",
                justifyContent: "flex-end",
                marginTop: "0.25rem",
              }}
            >
              <button
                type="button"
                onClick={onCancel}
                style={{
                  padding: "0.5rem 1rem",
                  border: "1px solid var(--color-border)",
                  borderRadius: "var(--border-radius)",
                  background: "var(--color-surface)",
                  cursor: "pointer",
                  fontFamily: "inherit",
                  fontSize: "0.875rem",
                }}
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={saving}
                data-testid="ticket-form-submit"
                style={{
                  padding: "0.5rem 1.25rem",
                  border: "none",
                  borderRadius: "var(--border-radius)",
                  background: "var(--color-primary)",
                  color: "#fff",
                  cursor: saving ? "not-allowed" : "pointer",
                  fontFamily: "inherit",
                  fontSize: "0.875rem",
                  fontWeight: 600,
                }}
              >
                {saving
                  ? mode === "create"
                    ? "Creating…"
                    : "Saving…"
                  : mode === "create"
                    ? "Create Ticket"
                    : "Save Changes"}
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}

package com.weeklycommit.carryforward.controller;

import com.weeklycommit.carryforward.dto.CarryForwardLineageResponse;
import com.weeklycommit.carryforward.dto.CarryForwardRequest;
import com.weeklycommit.carryforward.dto.CarryForwardResponse;
import com.weeklycommit.carryforward.service.CarryForwardService;
import jakarta.validation.Valid;
import java.util.UUID;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for carry-forward operations.
 *
 * <ul>
 * <li>{@code POST /api/plans/{id}/commits/{commitId}/carry-forward} — carry a
 * commit forward into a target week</li>
 * <li>{@code GET /api/commits/{id}/lineage} — retrieve the full carry-forward
 * ancestry chain</li>
 * </ul>
 */
@RestController
public class CarryForwardController {

	private final CarryForwardService carryForwardService;

	public CarryForwardController(CarryForwardService carryForwardService) {
		this.carryForwardService = carryForwardService;
	}

	/**
	 * Carries a commit forward into the target week's plan.
	 *
	 * @param planId
	 *            plan that currently owns the commit (path binding only — verified
	 *            server-side against the commit's plan)
	 * @param commitId
	 *            commit to carry forward
	 * @param request
	 *            target week, reason, and optional free-text
	 * @param actorId
	 *            actor user ID from header (falls back to request.actorUserId())
	 * @return 201 Created with the new commit and provenance link
	 */
	@PostMapping("/api/plans/{planId}/commits/{commitId}/carry-forward")
	public ResponseEntity<CarryForwardResponse> carryForward(@PathVariable UUID planId, @PathVariable UUID commitId,
			@Valid @RequestBody CarryForwardRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorId) {

		UUID actor = actorId != null ? actorId : request.actorUserId();
		CarryForwardResponse response = carryForwardService.carryForward(planId, commitId, request.targetWeekStart(),
				request.reason(), request.reasonText(), actor);
		return ResponseEntity.status(HttpStatus.CREATED).body(response);
	}

	/**
	 * Returns the full carry-forward ancestry chain for a commit.
	 *
	 * @param commitId
	 *            starting commit (may be any point in the chain)
	 * @return lineage ordered oldest-first
	 */
	@GetMapping("/api/commits/{commitId}/lineage")
	public ResponseEntity<CarryForwardLineageResponse> getLineage(@PathVariable UUID commitId) {
		return ResponseEntity.ok(carryForwardService.getCarryForwardLineage(commitId));
	}
}

package com.weeklycommit.carryforward.service;

import com.weeklycommit.carryforward.dto.CarryForwardLinkResponse;
import com.weeklycommit.carryforward.dto.CarryForwardLineageResponse;
import com.weeklycommit.carryforward.dto.CarryForwardResponse;
import com.weeklycommit.domain.entity.CarryForwardLink;
import com.weeklycommit.domain.entity.ScopeChangeEvent;
import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.CarryForwardReason;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.enums.ScopeChangeCategory;
import com.weeklycommit.domain.repository.CarryForwardLinkRepository;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.UserAccountRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.plan.service.WeeklyPlanService;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.time.LocalDate;
import java.time.ZoneOffset;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Implements PRD §13 FR-6 — carry-forward logic.
 *
 * <p>
 * A carry-forward copies a commit's core fields into a new commit in a target
 * week's plan, preserving provenance via a {@link CarryForwardLink}. The streak
 * counter tracks how many consecutive weeks a commit has been carried forward.
 */
@Service
@Transactional
public class CarryForwardService {

	private final WeeklyCommitRepository commitRepo;
	private final WeeklyPlanRepository planRepo;
	private final UserAccountRepository userRepo;
	private final CarryForwardLinkRepository linkRepo;
	private final ScopeChangeEventRepository scopeChangeEventRepo;

	public CarryForwardService(WeeklyCommitRepository commitRepo, WeeklyPlanRepository planRepo,
			UserAccountRepository userRepo, CarryForwardLinkRepository linkRepo,
			ScopeChangeEventRepository scopeChangeEventRepo) {
		this.commitRepo = commitRepo;
		this.planRepo = planRepo;
		this.userRepo = userRepo;
		this.linkRepo = linkRepo;
		this.scopeChangeEventRepo = scopeChangeEventRepo;
	}

	// -------------------------------------------------------------------------
	// carryForward
	// -------------------------------------------------------------------------

	/**
	 * Carries a commit forward into the target week's plan.
	 *
	 * <ul>
	 * <li>Copies title, description, chess piece, RCDO link, estimate points.</li>
	 * <li>Sets {@code carryForwardSourceId} and increments
	 * {@code carryForwardStreak} (source streak + 1).</li>
	 * <li>New commit is inserted at the bottom of the target plan's priority
	 * order.</li>
	 * <li>If the target week plan does not exist, it is lazily created.</li>
	 * <li>If the target plan is already LOCKED, the commit is added as a post-lock
	 * scope change event (COMMIT_ADDED with carry-forward reason).</li>
	 * </ul>
	 *
	 * @param sourceCommitId
	 *            commit to carry forward
	 * @param targetWeekStart
	 *            Monday of the target week
	 * @param reason
	 *            controlled enum reason
	 * @param reasonText
	 *            optional free-text elaboration
	 * @param actorUserId
	 *            user initiating the operation
	 * @return carry-forward response with new commit and provenance link
	 */
	public CarryForwardResponse carryForward(UUID planId, UUID sourceCommitId, LocalDate targetWeekStart,
			CarryForwardReason reason, String reasonText, UUID actorUserId) {

		WeeklyCommit source = requireCommit(sourceCommitId);
		validateCommitBelongsToPlan(planId, source);
		UUID ownerUserId = source.getOwnerUserId();

		// Get or lazily create the target week plan
		WeeklyPlan targetPlan = getOrCreateTargetPlan(ownerUserId, targetWeekStart);
		boolean postLockAdded = targetPlan.getState() == PlanState.LOCKED;

		// Build the new commit (provenance fields set regardless of plan state)
		WeeklyCommit newCommit = buildNewCommit(source, targetPlan);
		WeeklyCommit saved = commitRepo.save(newCommit);

		// If the target plan is LOCKED, record a scope-change event
		if (postLockAdded) {
			recordCarryForwardScopeChangeEvent(targetPlan.getId(), saved, reason, reasonText, actorUserId);
		}

		// Persist the provenance link
		CarryForwardLink link = new CarryForwardLink();
		link.setSourceCommitId(sourceCommitId);
		link.setTargetCommitId(saved.getId());
		link.setReason(reason);
		link.setReasonNotes(reasonText);
		CarryForwardLink savedLink = linkRepo.save(link);

		return new CarryForwardResponse(CommitResponse.from(saved), CarryForwardLinkResponse.from(savedLink),
				postLockAdded);
	}

	// -------------------------------------------------------------------------
	// getCarryForwardLineage
	// -------------------------------------------------------------------------

	/**
	 * Returns the full carry-forward ancestry chain for {@code commitId}.
	 *
	 * <p>
	 * Traverses both ancestors (via {@code carryForwardSourceId} on the commit
	 * entity) and descendants (via {@link CarryForwardLinkRepository}) to produce a
	 * complete, ordered chain from the oldest ancestor to the youngest descendant.
	 *
	 * @param commitId
	 *            starting commit
	 * @return full lineage ordered oldest-first
	 */
	@Transactional(readOnly = true)
	public CarryForwardLineageResponse getCarryForwardLineage(UUID commitId) {
		requireCommit(commitId);

		// Walk ancestors (upward)
		List<CarryForwardLink> ancestors = new LinkedList<>();
		UUID cursor = commitId;
		while (true) {
			WeeklyCommit c = commitRepo.findById(cursor).orElse(null);
			if (c == null || c.getCarryForwardSourceId() == null) {
				break;
			}
			Optional<CarryForwardLink> link = linkRepo.findByTargetCommitId(cursor);
			link.ifPresent(l -> ancestors.add(0, l)); // prepend — oldest first
			cursor = c.getCarryForwardSourceId();
		}
		UUID rootCommitId = cursor;

		// Walk descendants (downward) starting from commitId
		List<CarryForwardLink> descendants = new ArrayList<>();
		cursor = commitId;
		while (true) {
			List<CarryForwardLink> links = linkRepo.findBySourceCommitId(cursor);
			if (links.isEmpty()) {
				break;
			}
			// Take the first descendant (one-to-one chain is the normal case)
			CarryForwardLink next = links.get(0);
			descendants.add(next);
			cursor = next.getTargetCommitId();
		}

		List<CarryForwardLink> chain = new ArrayList<>();
		chain.addAll(ancestors);
		chain.addAll(descendants);

		List<CarryForwardLinkResponse> responses = chain.stream().map(CarryForwardLinkResponse::from).toList();
		return new CarryForwardLineageResponse(rootCommitId, responses);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private WeeklyCommit requireCommit(UUID commitId) {
		return commitRepo.findById(commitId)
				.orElseThrow(() -> new ResourceNotFoundException("Commit not found: " + commitId));
	}

	private void validateCommitBelongsToPlan(UUID planId, WeeklyCommit commit) {
		if (!commit.getPlanId().equals(planId)) {
			throw new PlanValidationException("Commit " + commit.getId() + " does not belong to plan " + planId);
		}
	}

	/**
	 * Fetches an existing plan for the owner+week or lazily creates one. This
	 * mirrors the logic in {@link WeeklyPlanService} but is intentionally
	 * self-contained to avoid a circular service dependency.
	 */
	private WeeklyPlan getOrCreateTargetPlan(UUID ownerUserId, LocalDate targetWeekStart) {
		return planRepo.findByOwnerUserIdAndWeekStartDate(ownerUserId, targetWeekStart)
				.orElseGet(() -> createTargetPlan(ownerUserId, targetWeekStart));
	}

	private WeeklyPlan createTargetPlan(UUID ownerUserId, LocalDate weekStartDate) {
		UserAccount user = userRepo.findById(ownerUserId)
				.orElseThrow(() -> new ResourceNotFoundException("User not found: " + ownerUserId));

		if (user.getHomeTeamId() == null) {
			throw new PlanValidationException(
					"User " + ownerUserId + " has no home team; cannot create a carry-forward plan");
		}

		WeeklyPlan plan = new WeeklyPlan();
		plan.setOwnerUserId(ownerUserId);
		plan.setTeamId(user.getHomeTeamId());
		plan.setWeekStartDate(weekStartDate);
		plan.setState(PlanState.DRAFT);
		plan.setCapacityBudgetPoints(user.getWeeklyCapacityPoints());
		plan.setLockDeadline(weekStartDate.atTime(12, 0).toInstant(ZoneOffset.UTC));
		plan.setReconcileDeadline(weekStartDate.plusDays(7).atTime(10, 0).toInstant(ZoneOffset.UTC));
		return planRepo.save(plan);
	}

	private WeeklyCommit buildNewCommit(WeeklyCommit source, WeeklyPlan targetPlan) {
		WeeklyCommit c = new WeeklyCommit();
		c.setPlanId(targetPlan.getId());
		c.setOwnerUserId(source.getOwnerUserId());
		c.setTitle(source.getTitle());
		c.setDescription(source.getDescription());
		c.setChessPiece(source.getChessPiece());
		c.setRcdoNodeId(source.getRcdoNodeId());
		c.setEstimatePoints(source.getEstimatePoints());
		c.setSuccessCriteria(source.getSuccessCriteria());
		// Provenance
		c.setCarryForwardSourceId(source.getId());
		c.setCarryForwardStreak(source.getCarryForwardStreak() + 1);
		// Bottom of priority order
		c.setPriorityOrder((int) (commitRepo.countByPlanId(targetPlan.getId()) + 1));
		return c;
	}

	/**
	 * Records a COMMIT_ADDED scope-change event when carry-forward targets a LOCKED
	 * plan.
	 */
	private void recordCarryForwardScopeChangeEvent(UUID planId, WeeklyCommit commit, CarryForwardReason reason,
			String reasonText, UUID actorUserId) {
		ScopeChangeEvent event = new ScopeChangeEvent();
		event.setPlanId(planId);
		event.setCommitId(commit.getId());
		event.setCategory(ScopeChangeCategory.COMMIT_ADDED);
		event.setChangedByUserId(
				actorUserId != null ? actorUserId : UUID.fromString("00000000-0000-0000-0000-000000000000"));
		String reasonLabel = "CARRY_FORWARD:" + reason.name() + (reasonText != null ? " — " + reasonText : "");
		event.setReason(reasonLabel);
		event.setPreviousValue(null);
		// Minimal JSON payload matching what ScopeChangeService would produce
		event.setNewValue("{\"carryForward\":true,\"chessPiece\":\""
				+ (commit.getChessPiece() != null ? commit.getChessPiece().name() : "") + "\",\"title\":"
				+ quoteJson(commit.getTitle()) + "}");
		scopeChangeEventRepo.save(event);
	}

	private static String quoteJson(String s) {
		if (s == null) {
			return "null";
		}
		return "\"" + s.replace("\\", "\\\\").replace("\"", "\\\"") + "\"";
	}
}

package com.weeklycommit.carryforward.dto;

import java.util.List;
import java.util.UUID;

/**
 * Full carry-forward ancestry chain for a given commit.
 *
 * <p>
 * {@code chain} is ordered from the oldest ancestor to the most recent
 * descendant. Each element represents one generation of carry-forward. The
 * queried commit may appear in the middle of the chain if it has both ancestors
 * and descendants.
 *
 * @param rootCommitId
 *            the oldest commit in the lineage (no carry-forward source)
 * @param chain
 *            ordered list of carry-forward links forming the ancestry
 */
public record CarryForwardLineageResponse(UUID rootCommitId, List<CarryForwardLinkResponse> chain) {
}

package com.weeklycommit.carryforward.dto;

import com.weeklycommit.domain.entity.CarryForwardLink;
import com.weeklycommit.domain.enums.CarryForwardReason;
import java.time.Instant;
import java.util.UUID;

/**
 * Immutable view of a single carry-forward lineage link.
 */
public record CarryForwardLinkResponse(UUID id, UUID sourceCommitId, UUID targetCommitId, CarryForwardReason reason,
		String reasonText, Instant createdAt) {

	public static CarryForwardLinkResponse from(CarryForwardLink link) {
		return new CarryForwardLinkResponse(link.getId(), link.getSourceCommitId(), link.getTargetCommitId(),
				link.getReason(), link.getReasonNotes(), link.getCreatedAt());
	}
}

package com.weeklycommit.team.controller;

import com.weeklycommit.team.dto.AddCommentRequest;
import com.weeklycommit.team.dto.CapacityOverrideResponse;
import com.weeklycommit.team.dto.CommentResponse;
import com.weeklycommit.team.dto.ExceptionResponse;
import com.weeklycommit.team.dto.ResolveExceptionRequest;
import com.weeklycommit.team.dto.SetCapacityOverrideRequest;
import com.weeklycommit.team.dto.TeamWeekViewResponse;
import com.weeklycommit.team.service.ManagerReviewService;
import com.weeklycommit.team.service.TeamWeeklyViewService;
import jakarta.validation.Valid;
import java.time.LocalDate;
import java.util.List;
import java.util.UUID;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for team weekly view, manager review, and exception
 * management.
 *
 * <ul>
 * <li>{@code GET /api/teams/{id}/week/{weekStart}} — team weekly view</li>
 * <li>{@code GET /api/teams/{id}/week/{weekStart}/exceptions} — exception
 * queue</li>
 * <li>{@code POST /api/comments} — add manager comment</li>
 * <li>{@code PUT  /api/capacity-overrides} — set capacity override</li>
 * <li>{@code PUT /api/exceptions/{id}/resolve} — resolve exception</li>
 * </ul>
 */
@RestController
public class TeamController {

	private final TeamWeeklyViewService teamViewService;
	private final ManagerReviewService managerReviewService;

	public TeamController(TeamWeeklyViewService teamViewService, ManagerReviewService managerReviewService) {
		this.teamViewService = teamViewService;
		this.managerReviewService = managerReviewService;
	}

	// -------------------------------------------------------------------------
	// Team weekly view
	// -------------------------------------------------------------------------

	/**
	 * Returns the aggregated weekly view for all team members. Full detail for
	 * managers; peer-filtered view for ICs.
	 */
	@GetMapping("/api/teams/{id}/week/{weekStart}")
	public ResponseEntity<TeamWeekViewResponse> getTeamWeekView(@PathVariable UUID id,
			@PathVariable @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate weekStart,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		return ResponseEntity.ok(teamViewService.getTeamWeekView(id, weekStart, callerId));
	}

	// -------------------------------------------------------------------------
	// Exception queue
	// -------------------------------------------------------------------------

	/**
	 * Returns the unresolved manager-review exception queue for a team + week,
	 * detecting new exceptions from current plan data. Ordered by severity.
	 */
	@GetMapping("/api/teams/{id}/week/{weekStart}/exceptions")
	public ResponseEntity<List<ExceptionResponse>> getExceptionQueue(@PathVariable UUID id,
			@PathVariable @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate weekStart,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		return ResponseEntity.ok(managerReviewService.getExceptionQueue(id, weekStart, callerId));
	}

	// -------------------------------------------------------------------------
	// Comments
	// -------------------------------------------------------------------------

	/**
	 * Adds a manager comment on a plan or commit. Only the direct manager of the
	 * plan/commit owner may comment.
	 */
	@PostMapping("/api/comments")
	public ResponseEntity<CommentResponse> addComment(@Valid @RequestBody AddCommentRequest request) {
		String targetType = request.planId() != null ? "PLAN" : "COMMIT";
		UUID targetId = request.planId() != null ? request.planId() : request.commitId();

		if (targetId == null) {
			return ResponseEntity.badRequest().build();
		}

		CommentResponse response = managerReviewService.addComment(targetType, targetId, request.managerId(),
				request.text());
		return ResponseEntity.status(HttpStatus.CREATED).body(response);
	}

	// -------------------------------------------------------------------------
	// Capacity override
	// -------------------------------------------------------------------------

	/**
	 * Sets (or updates) the capacity budget override for a user for a specific
	 * week. Also updates the associated plan's budget if a plan exists.
	 */
	@PutMapping("/api/capacity-overrides")
	public ResponseEntity<CapacityOverrideResponse> setCapacityOverride(
			@Valid @RequestBody SetCapacityOverrideRequest request) {
		CapacityOverrideResponse response = managerReviewService.setCapacityOverride(request.managerId(),
				request.userId(), request.weekStartDate(), request.overridePoints(), request.reason());
		return ResponseEntity.ok(response);
	}

	// -------------------------------------------------------------------------
	// Resolve exception
	// -------------------------------------------------------------------------

	/**
	 * Marks a manager-review exception as resolved with a required resolution note.
	 */
	@PutMapping("/api/exceptions/{id}/resolve")
	public ResponseEntity<ExceptionResponse> resolveException(@PathVariable UUID id,
			@Valid @RequestBody ResolveExceptionRequest request) {
		return ResponseEntity.ok(managerReviewService.resolveException(id, request.resolution(), request.resolverId()));
	}
}

/**
 * PlanHistoryView — week-by-week plan history for the current user.
 *
 * Each row shows: week start, plan state, compliance, commit count,
 * total planned/achieved points, carry-forward count.
 * Clicking a row expands to show full plan detail via linked navigation.
 */
import { useState } from "react";
import type { WeeklyPlanHistoryEntry } from "../../api/ticketTypes.js";
import type { PlanState } from "../../api/planTypes.js";

export interface PlanHistoryViewProps {
  readonly entries: WeeklyPlanHistoryEntry[];
  readonly loading: boolean;
  /** Called when user wants to navigate to a historical plan. */
  readonly onViewPlan?: (planId: string, weekStart: string) => void;
}

const STATE_BADGE_COLORS: Record<
  PlanState,
  { background: string; color: string }
> = {
  DRAFT: { background: "#fef3c7", color: "#92400e" },
  LOCKED: { background: "#dbeafe", color: "#1e40af" },
  RECONCILING: { background: "#fde68a", color: "#78350f" },
  RECONCILED: { background: "#d1fae5", color: "#065f46" },
};

function PlanStateBadge({ state }: { readonly state: PlanState }) {
  const { background, color } = STATE_BADGE_COLORS[state];
  return (
    <span
      style={{
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "0.7rem",
        fontWeight: 700,
        background,
        color,
        display: "inline-block",
      }}
    >
      {state}
    </span>
  );
}

function formatWeekLabel(isoDate: string): string {
  const d = new Date(`${isoDate}T00:00:00`);
  return d.toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
}

export function PlanHistoryView({
  entries,
  loading,
  onViewPlan,
}: PlanHistoryViewProps) {
  const [expandedPlanId, setExpandedPlanId] = useState<string | null>(null);

  if (loading) {
    return (
      <div
        data-testid="plan-history-loading"
        role="status"
        aria-label="Loading plan history"
        style={{ color: "var(--color-text-muted)", fontSize: "0.875rem" }}
      >
        Loading history…
      </div>
    );
  }

  if (entries.length === 0) {
    return (
      <div
        data-testid="plan-history-empty"
        style={{
          padding: "1.5rem",
          textAlign: "center",
          color: "var(--color-text-muted)",
          fontSize: "0.9rem",
        }}
      >
        No historical plans found.
      </div>
    );
  }

  // Sort chronologically (newest first)
  const sorted = [...entries].sort(
    (a, b) =>
      new Date(b.weekStartDate).getTime() - new Date(a.weekStartDate).getTime(),
  );

  return (
    <section
      data-testid="plan-history-view"
      aria-labelledby="plan-history-heading"
    >
      <h3
        id="plan-history-heading"
        style={{ margin: "0 0 0.75rem", fontSize: "0.95rem", fontWeight: 700 }}
      >
        Plan History
      </h3>
      <div style={{ overflowX: "auto" }}>
        <table
          data-testid="plan-history-table"
          style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.875rem" }}
        >
          <thead>
            <tr>
              <th style={thStyle}>Week</th>
              <th style={thStyle}>State</th>
              <th style={thStyle}>Compliant</th>
              <th style={thStyle}>Commits</th>
              <th style={thStyle}>Planned Pts</th>
              <th style={thStyle}>Achieved Pts</th>
              <th style={thStyle}>Carry-fwd</th>
              <th style={thStyle}></th>
            </tr>
          </thead>
          <tbody>
            {sorted.map((entry) => (
              <>
                <tr
                  key={entry.planId}
                  data-testid={`plan-history-row-${entry.planId}`}
                  onClick={() =>
                    setExpandedPlanId(
                      expandedPlanId === entry.planId ? null : entry.planId,
                    )
                  }
                  style={{
                    cursor: "pointer",
                    background:
                      expandedPlanId === entry.planId
                        ? "var(--color-background)"
                        : undefined,
                  }}
                >
                  <td style={tdStyle}>
                    <span data-testid={`plan-history-week-${entry.planId}`}>
                      {formatWeekLabel(entry.weekStartDate)}
                    </span>
                  </td>
                  <td style={tdStyle}>
                    <PlanStateBadge state={entry.planState} />
                  </td>
                  <td style={tdStyle}>
                    {entry.compliant ? (
                      <span
                        data-testid={`plan-history-compliant-${entry.planId}`}
                        style={{ color: "var(--color-success)", fontWeight: 700 }}
                      >
                        ✓
                      </span>
                    ) : (
                      <span
                        data-testid={`plan-history-noncompliant-${entry.planId}`}
                        style={{ color: "var(--color-danger)" }}
                      >
                        ✗
                      </span>
                    )}
                  </td>
                  <td
                    style={{ ...tdStyle, textAlign: "center" }}
                    data-testid={`plan-history-commits-${entry.planId}`}
                  >
                    {entry.commitCount}
                  </td>
                  <td
                    style={{ ...tdStyle, textAlign: "center" }}
                    data-testid={`plan-history-planned-${entry.planId}`}
                  >
                    {entry.plannedPoints}
                  </td>
                  <td style={{ ...tdStyle, textAlign: "center" }}>
                    <span
                      data-testid={`plan-history-achieved-${entry.planId}`}
                      style={{
                        color:
                          entry.planState === "RECONCILED"
                            ? "var(--color-success)"
                            : "var(--color-text-muted)",
                      }}
                    >
                      {entry.achievedPoints}
                    </span>
                  </td>
                  <td style={{ ...tdStyle, textAlign: "center" }}>
                    {entry.carryForwardCount > 0 ? (
                      <span
                        data-testid={`plan-history-cf-${entry.planId}`}
                        style={{
                          background: "#fef3c7",
                          color: "#92400e",
                          padding: "1px 7px",
                          borderRadius: "999px",
                          fontSize: "0.75rem",
                          fontWeight: 600,
                        }}
                      >
                        {entry.carryForwardCount} CF
                      </span>
                    ) : (
                      <span style={{ color: "var(--color-text-muted)" }}>—</span>
                    )}
                  </td>
                  <td style={{ ...tdStyle, textAlign: "right" }}>
                    <span style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
                      {expandedPlanId === entry.planId ? "▲" : "▼"}
                    </span>
                  </td>
                </tr>

                {/* Expanded detail row */}
                {expandedPlanId === entry.planId && (
                  <tr
                    key={`${entry.planId}-expanded`}
                    data-testid={`plan-history-expanded-${entry.planId}`}
                  >
                    <td
                      colSpan={8}
                      style={{
                        padding: "0.875rem 1.25rem",
                        background: "var(--color-background)",
                        borderBottom: "1px solid var(--color-border)",
                      }}
                    >
                      <div
                        style={{
                          display: "flex",
                          gap: "1rem",
                          alignItems: "center",
                          flexWrap: "wrap",
                        }}
                      >
                        <span style={{ fontSize: "0.85rem" }}>
                          Week of <strong>{formatWeekLabel(entry.weekStartDate)}</strong>
                          {" — "}
                          <strong>{entry.planState}</strong>
                        </span>
                        {onViewPlan && (
                          <button
                            type="button"
                            onClick={(e) => {
                              e.stopPropagation();
                              onViewPlan(entry.planId, entry.weekStartDate);
                            }}
                            data-testid={`plan-history-view-btn-${entry.planId}`}
                            style={{
                              padding: "0.3rem 0.75rem",
                              border: "1px solid var(--color-border)",
                              borderRadius: "var(--border-radius)",
                              background: "var(--color-surface)",
                              cursor: "pointer",
                              fontFamily: "inherit",
                              fontSize: "0.8rem",
                            }}
                          >
                            View Full Plan →
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                )}
              </>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
}

const thStyle: React.CSSProperties = {
  padding: "0.5rem 0.625rem",
  textAlign: "left",
  fontSize: "0.75rem",
  fontWeight: 700,
  textTransform: "uppercase",
  letterSpacing: "0.04em",
  color: "var(--color-text-muted)",
  borderBottom: "2px solid var(--color-border)",
  whiteSpace: "nowrap",
};

const tdStyle: React.CSSProperties = {
  padding: "0.5rem 0.625rem",
  fontSize: "0.875rem",
  borderBottom: "1px solid var(--color-border)",
  verticalAlign: "middle",
};

/**
 * TeamHistoryView — weekly trend table for the team.
 *
 * Columns: week, member count, compliance rate, planned pts, achieved pts,
 * carry-forward rate, exception count.
 * Shows week-over-week delta indicators for key metrics.
 */
import type { TeamWeekHistoryEntry } from "../../api/ticketTypes.js";

export interface TeamHistoryViewProps {
  readonly entries: TeamWeekHistoryEntry[];
  readonly loading: boolean;
}

function formatPct(value: number): string {
  return `${Math.round(value * 100)}%`;
}

function formatWeekLabel(isoDate: string): string {
  const d = new Date(`${isoDate}T00:00:00`);
  return d.toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
  });
}

function DeltaIndicator({
  current,
  previous,
  higherIsBetter = true,
}: {
  readonly current: number;
  readonly previous: number | undefined;
  readonly higherIsBetter?: boolean;
}) {
  if (previous === undefined) return null;
  const delta = current - previous;
  if (delta === 0) return null;
  const isGood = higherIsBetter ? delta > 0 : delta < 0;
  return (
    <span
      style={{
        marginLeft: "0.25rem",
        fontSize: "0.7rem",
        color: isGood ? "var(--color-success)" : "var(--color-danger)",
        fontWeight: 600,
      }}
    >
      {delta > 0 ? "▲" : "▼"}{Math.abs(Math.round(delta * 100) / 100)}
    </span>
  );
}

export function TeamHistoryView({ entries, loading }: TeamHistoryViewProps) {
  if (loading) {
    return (
      <div
        data-testid="team-history-loading"
        role="status"
        aria-label="Loading team history"
        style={{ color: "var(--color-text-muted)", fontSize: "0.875rem" }}
      >
        Loading team history…
      </div>
    );
  }

  if (entries.length === 0) {
    return (
      <div
        data-testid="team-history-empty"
        style={{
          padding: "1.5rem",
          textAlign: "center",
          color: "var(--color-text-muted)",
          fontSize: "0.9rem",
        }}
      >
        No team history available yet.
      </div>
    );
  }

  // Sort newest first
  const sorted = [...entries].sort(
    (a, b) =>
      new Date(b.weekStartDate).getTime() - new Date(a.weekStartDate).getTime(),
  );

  return (
    <section
      data-testid="team-history-view"
      aria-labelledby="team-history-heading"
    >
      <h3
        id="team-history-heading"
        style={{ margin: "0 0 0.75rem", fontSize: "0.95rem", fontWeight: 700 }}
      >
        Team History
      </h3>
      <div style={{ overflowX: "auto" }}>
        <table
          data-testid="team-history-table"
          style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.875rem" }}
        >
          <thead>
            <tr>
              <th style={thStyle}>Week</th>
              <th style={thStyle}>Members</th>
              <th style={thStyle}>Compliance %</th>
              <th style={thStyle}>Planned Pts</th>
              <th style={thStyle}>Achieved Pts</th>
              <th style={thStyle}>CF Rate</th>
              <th style={thStyle}>Exceptions</th>
            </tr>
          </thead>
          <tbody>
            {sorted.map((entry, idx) => {
              const prev = sorted[idx + 1]; // previous week (older)
              return (
                <tr
                  key={entry.weekStartDate}
                  data-testid={`team-history-row-${entry.weekStartDate}`}
                >
                  <td style={tdStyle}>
                    <span
                      data-testid={`team-history-week-${entry.weekStartDate}`}
                      style={{ fontWeight: 600 }}
                    >
                      {formatWeekLabel(entry.weekStartDate)}
                    </span>
                  </td>
                  <td style={{ ...tdStyle, textAlign: "center" }}>
                    {entry.memberCount}
                  </td>
                  <td style={tdStyle}>
                    <span
                      data-testid={`team-history-compliance-${entry.weekStartDate}`}
                      style={{
                        color:
                          entry.complianceRate >= 0.8
                            ? "var(--color-success)"
                            : entry.complianceRate >= 0.5
                              ? "var(--color-warning)"
                              : "var(--color-danger)",
                        fontWeight: 600,
                      }}
                    >
                      {formatPct(entry.complianceRate)}
                    </span>
                    <DeltaIndicator
                      current={entry.complianceRate}
                      previous={prev?.complianceRate}
                      higherIsBetter
                    />
                  </td>
                  <td style={{ ...tdStyle, textAlign: "center" }}>
                    <span data-testid={`team-history-planned-${entry.weekStartDate}`}>
                      {entry.plannedPoints}
                    </span>
                    <DeltaIndicator
                      current={entry.plannedPoints}
                      previous={prev?.plannedPoints}
                      higherIsBetter
                    />
                  </td>
                  <td style={{ ...tdStyle, textAlign: "center" }}>
                    <span
                      data-testid={`team-history-achieved-${entry.weekStartDate}`}
                      style={{
                        color:
                          entry.achievedPoints > 0
                            ? "var(--color-success)"
                            : "var(--color-text-muted)",
                      }}
                    >
                      {entry.achievedPoints}
                    </span>
                    <DeltaIndicator
                      current={entry.achievedPoints}
                      previous={prev?.achievedPoints}
                      higherIsBetter
                    />
                  </td>
                  <td style={tdStyle}>
                    <span
                      data-testid={`team-history-cf-rate-${entry.weekStartDate}`}
                      style={{
                        color:
                          entry.carryForwardRate > 0.3
                            ? "var(--color-warning)"
                            : "var(--color-text)",
                      }}
                    >
                      {formatPct(entry.carryForwardRate)}
                    </span>
                    <DeltaIndicator
                      current={entry.carryForwardRate}
                      previous={prev?.carryForwardRate}
                      higherIsBetter={false}
                    />
                  </td>
                  <td style={{ ...tdStyle, textAlign: "center" }}>
                    <span
                      data-testid={`team-history-exceptions-${entry.weekStartDate}`}
                      style={{
                        color:
                          entry.exceptionCount > 0
                            ? "var(--color-danger)"
                            : "var(--color-text-muted)",
                        fontWeight: entry.exceptionCount > 0 ? 600 : undefined,
                      }}
                    >
                      {entry.exceptionCount}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </section>
  );
}

const thStyle: React.CSSProperties = {
  padding: "0.5rem 0.625rem",
  textAlign: "left",
  fontSize: "0.75rem",
  fontWeight: 700,
  textTransform: "uppercase",
  letterSpacing: "0.04em",
  color: "var(--color-text-muted)",
  borderBottom: "2px solid var(--color-border)",
  whiteSpace: "nowrap",
};

const tdStyle: React.CSSProperties = {
  padding: "0.5rem 0.625rem",
  fontSize: "0.875rem",
  borderBottom: "1px solid var(--color-border)",
